      const camelField = field.replace(/_([a-z])/g, (g) => g[1].toUpperCase());
      if (updates[camelField] !== undefined) {
        updateFields.push(`${field} = $${paramCount}`);
        updateValues.push(updates[camelField]);
        paramCount++;
      }
    });

    if (updateFields.length === 0) {
      return res.status(400).json({ error: 'No valid fields to update' });
    }

    updateValues.push(id, userId);
    const query = `
      UPDATE contacts
      SET ${updateFields.join(', ')}, updated_at = CURRENT_TIMESTAMP
      WHERE id = $${paramCount} AND user_id = $${paramCount + 1}
      RETURNING *
    `;

    const result = await client.query(query, updateValues);

    // Log activity
    await client.query(
      `INSERT INTO activity_log (user_id, entity_type, entity_id, action, changes)
       VALUES ($1, $2, $3, $4, $5)`,
      [userId, 'contact', id, 'updated', JSON.stringify({
        before: existing,
        after: result.rows[0]
      })]
    );

    await client.query('COMMIT');

    res.json({
      message: 'Contact updated successfully',
      contact: result.rows[0]
    });
  } catch (error) {
    await client.query('ROLLBACK');
    console.error(error);
    res.status(500).json({ error: 'Failed to update contact' });
  } finally {
    client.release();
  }
});

// Soft delete contact
router.delete('/:id', async (req, res) => {
  try {
    const { id } = req.params;
    const userId = req.user.id;

    const result = await pool.query(
      `UPDATE contacts
       SET deleted_at = CURRENT_TIMESTAMP
       WHERE id = $1 AND user_id = $2
       RETURNING *`,
      [id, userId]
    );

    if (result.rows.length === 0) {
      return res.status(404).json({ error: 'Contact not found' });
    }

    res.json({ message: 'Contact deleted successfully' });
  } catch (error) {
    console.error(error);
    res.status(500).json({ error: 'Failed to delete contact' });
  }
});

// Bulk import
router.post('/import/csv', async (req, res) => {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');

    const { contacts } = req.body; // CSV parsed to JSON
    const userId = req.user.id;
    const importedContacts = [];

    for (const contact of contacts) {
      const contactId = uuidv4();
      const result = await client.query(
        `INSERT INTO contacts
         (id, user_id, first_name, last_name, email, phone, company, job_title)
         VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
         ON CONFLICT (user_id, email, phone) DO UPDATE SET
           updated_at = CURRENT_TIMESTAMP
         RETURNING *`,
        [contactId, userId, contact.firstName, contact.lastName, 
         contact.email, contact.phone, contact.company, contact.jobTitle]
      );
      importedContacts.push(result.rows[0]);
    }

    await client.query('COMMIT');

    res.json({
      message: `Imported ${importedContacts.length} contacts`,
      contacts: importedContacts
    });
  } catch (error) {
    await client.query('ROLLBACK');
    console.error(error);
    res.status(500).json({ error: 'Failed to import contacts' });
  } finally {
    client.release();
  }
});

// Export contacts
router.get('/export/csv', async (req, res) => {
  try {
    const userId = req.user.id;

    const result = await pool.query(
      `SELECT first_name, last_name, email, phone, company, job_title, notes
       FROM contacts
       WHERE user_id = $1 AND deleted_at IS NULL
       ORDER BY first_name, last_name`,
      [userId]
    );

    const csv = convertToCSV(result.rows);

    res.setHeader('Content-Type', 'text/csv');
    res.setHeader('Content-Disposition', 'attachment; filename="contacts.csv"');
    res.send(csv);
  } catch (error) {
    console.error(error);
    res.status(500).json({ error: 'Failed to export contacts' });
  }
});

module.exports = router;
