// src/components/ContactList.jsx
import React, { useState, useEffect, useCallback } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import axios from 'axios';
import ContactCard from './ContactCard';
import SearchBar from './SearchBar';
import Pagination from './Pagination';

const API_BASE = process.env.REACT_APP_API_URL;

export const ContactList = () => {
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState('');
  const [sort, setSort] = useState('name');
  const queryClient = useQueryClient();

  const { data, isLoading, error } = useQuery({
    queryKey: ['contacts', page, search, sort],
    queryFn: async () => {
      const response = await axios.get(`${API_BASE}/contacts`, {
        params: { page, search, sort, limit: 20 }
      });
      return response.data;
    }
  });

  const deleteContactMutation = useMutation(
    (contactId) => axios.delete(`${API_BASE}/contacts/${contactId}`),
    {
      onSuccess: () => {
        queryClient.invalidateQueries(['contacts']);
      }
    }
  );

  const handleDelete = (contactId) => {
    if (window.confirm('Are you sure?')) {
      deleteContactMutation.mutate(contactId);
    }
  };

  const handleSearch = useCallback((value) => {
    setSearch(value);
    setPage(1);
  }, []);

  if (isLoading) return <div className="spinner">Loading...</div>;
  if (error) return <div className="error">Error loading contacts</div>;

  return (
    <div className="contact-list">
      <div className="controls">
        <SearchBar onSearch={handleSearch} />
        <select 
          value={sort} 
          onChange={(e) => setSort(e.target.value)}
          className="sort-select"
        >
          <option value="name">Sort by Name</option>
          <option value="recent">Sort by Recent</option>
          <option value="favorite">Favorites First</option>
        </select>
      </div>

      <div className="contacts-grid">
        {data?.data.map(contact => (
          <ContactCard
            key={contact.id}
            contact={contact}
            onDelete={handleDelete}
          />
        ))}
      </div>

      {data && (
        <Pagination
          current={page}
          total={data.pagination.pages}
          onPageChange={setPage}
        />
      )}
    </div>
  );
};

export default ContactList;
```

```javascript
// src/components/ContactForm.jsx
import React, { useState } from 'react';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import axios from 'axios';

const API_BASE = process.env.REACT_APP_API_URL;

export const ContactForm = ({ initialData = null, onSuccess = null }) => {
  const [formData, setFormData] = useState(initialData || {
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    company: '',
    jobTitle: '',
    notes: '',
    type: 'personal'
  });

  const [errors, setErrors] = useState({});
  const queryClient = useQueryClient();

  const createMutation = useMutation(
    (data) => axios.post(`${API_BASE}/contacts`, data),
    { onSuccess: () => queryClient.invalidateQueries(['contacts']) }
  );

  const updateMutation = useMutation(
    (data) => axios.put(`${API_BASE}/contacts/${initialData.id}`, data),
    { onSuccess: () => queryClient.invalidateQueries(['contacts']) }
  );

  const validateForm = () => {
    const newErrors = {};
    if (!formData.firstName.trim()) newErrors.firstName = 'First name required';
    if (formData.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
      newErrors.email = 'Invalid email';
    }
    if (formData.phone && !/^[\d\s\-\+\(\)]+$/.test(formData.phone)) {
      newErrors.phone = 'Invalid phone number';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateForm()) return;

    try {
      if (initialData) {
        await updateMutation.mutateAsync(formData);
      } else {
        await createMutation.mutateAsync(formData);
      }
      onSuccess?.();
      setFormData({
        firstName: '',
        lastName: '',
        email: '',
        phone: '',
        company: '',
        jobTitle: '',
        notes: '',
        type: 'personal'
      });
    } catch (error) {
      setErrors({ submit: error.response?.data?.error || 'Form submission failed' });
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
    if (errors[name]) {
      setErrors(prev => ({
        ...prev,
        [name]: ''
      }));
    }
  };

  return (
    <form onSubmit={handleSubmit} className="contact-form">
      <div className="form-row">
        <div className="form-group">
          <label htmlFor="firstName">First Name *</label>
          <input
            id="firstName"
            name="firstName"
            value={formData.firstName}
            onChange={handleChange}
            className={errors.firstName ? 'error' : ''}
            placeholder="John"
          />
          {errors.firstName && <span className="error-text">{errors.firstName}</span>}
        </div>

        <div className="form-group">
          <label htmlFor="lastName">Last Name</label>
          <input
            id="lastName"
            name="lastName"
            value={formData.lastName}
            onChange={handleChange}
            placeholder="Doe"
          />
        </div>
      </div>

      <div className="form-row">
        <div className="form-group">
          <label htmlFor="email">Email</label>
          <input
            id="email"
            name="email"
            type="email"
            value={formData.email}
            onChange={handleChange}
            className={errors.email ? 'error' : ''}
            placeholder="john@example.com"
          />
          {errors.email && <span className="error-text">{errors.email}</span>}
        </div>

        <div className="form-group">
          <label htmlFor="phone">Phone</label>
          <input
            id="phone"
            name="phone"
            value={formData.phone}
            onChange={handleChange}
            className={errors.phone ? 'error' : ''}
            placeholder="+1 (555) 000-0000"
          />
          {errors.phone && <span className="error-text">{errors.phone}</span>}
        </div>
      </div>

      <div className="form-row">
        <div className="form-group">
          <label htmlFor="company">Company</label>
          <input
            id="company"
            name="company"
            value={formData.company}
            onChange={handleChange}
            placeholder="Company name"
          />
        </div>

        <div className="form-group">
          <label htmlFor="jobTitle">Job Title</label>
          <input
            id="jobTitle"
            name="jobTitle"
            value={formData.jobTitle}
            onChange={handleChange}
            placeholder="Position"
          />
        </div>
      </div>

      <div className="form-group">
        <label htmlFor="type">Contact Type</label>
        <select
          id="type"
          name="type"
          value={formData.type}
          onChange={handleChange}
        >
          <option value="personal">Personal</option>
          <option value="business">Business</option>
          <option value="family">Family</option>
          <option value="other">Other</option>
        </select>
      </div>

      <div className="form-group">
        <label htmlFor="notes">Notes</label>
        <textarea
          id="notes"
          name="notes"
          value={formData.notes}
          onChange={handleChange}
          placeholder="Additional information..."
          rows="4"
        />
      </div>

      {errors.submit && <div className="error-banner">{errors.submit}</div>}

      <button 
        type="submit" 
        className="btn-primary"
        disabled={createMutation.isLoading || updateMutation.isLoading}
      >
        {initialData ? 'Update Contact' : 'Add Contact'}
      </button>
    </form>
  );
};

export default ContactForm;
```

