class OptimizedModel(context: Context) {
    private val interpreter: Interpreter
    private val inputBuffer: ByteBuffer

    init {
        val options = Interpreter.Options()
        options.setNumThreads(4)
        interpreter = Interpreter(loadModel(context), options)

        // Allocate reusable buffer
        inputBuffer = ByteBuffer.allocateDirect(
            224 * 224 * 3 * 4
        ).apply { order(ByteOrder.nativeOrder()) }
    }

    fun predict(bitmap: Bitmap): FloatArray {
        inputBuffer.clear()
        // Reuse buffer
        return FloatArray(1000).also {
            interpreter.run(inputBuffer, arrayOf(it))
        }
    }

    fun cleanup() {
        interpreter.close()
    }
}
